import{c as t,Q as a,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const r="/screenshots/portal-sidebar-light.png",n="/screenshots/portal-sidebar-dark.png",u=JSON.parse('{"title":"Customer Portal Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/portal/index.md","filePath":"guide/portal/index.md","lastUpdated":1778912818000}'),i={name:"guide/portal/index.md"};function d(l,e,c,h,g,p){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="customer-portal-overview" tabindex="-1">Customer Portal Overview <a class="header-anchor" href="#customer-portal-overview" aria-label="Permalink to &quot;Customer Portal Overview&quot;">​</a></h1><p>The <strong>Customer Portal</strong> is the workspace your customers see when they sign in. It is scoped to a single customer at a time and shows only that customer&#39;s tenants, users, billing, and configuration.</p><p>If you belong to more than one customer organisation, a <strong>customer switcher</strong> in the header lets you jump between them without signing out.</p><h2 id="sidebar-map" tabindex="-1">Sidebar map <a class="header-anchor" href="#sidebar-map" aria-label="Permalink to &quot;Sidebar map&quot;">​</a></h2><p><img src="'+r+'" alt="Customer Portal sidebar" class="light-only"><img src="'+n+'" alt="Customer Portal sidebar" class="dark-only"></p><p>The sidebar is short and focused. It is grouped into four sections:</p><table tabindex="0"><thead><tr><th>Section</th><th>What&#39;s there</th></tr></thead><tbody><tr><td><strong>Overview</strong></td><td><a href="./dashboard">Dashboard</a> — status at a glance.</td></tr><tr><td><strong>Workspace</strong></td><td><a href="./tenants">Tenants</a>, <a href="./instances">Instances</a>, <a href="./users">Users</a> — the things you work with day-to-day.</td></tr><tr><td><strong>Billing</strong></td><td><a href="./billing">Billing</a>, <a href="./changelog">What&#39;s New</a> — invoices, usage, and product updates.</td></tr><tr><td><strong>Account</strong></td><td><a href="./settings">Settings</a>, <a href="./account">Account</a> — organisation-wide configuration and personal account.</td></tr></tbody></table><p>If you are a <strong>member</strong> rather than an admin or owner, the sidebar is replaced by a smaller top-bar view, and pages you do not have access to are hidden.</p><h2 id="who-sees-what" tabindex="-1">Who sees what <a class="header-anchor" href="#who-sees-what" aria-label="Permalink to &quot;Who sees what&quot;">​</a></h2><p>Pages and actions are gated by <strong>portal roles</strong> and <strong>portal actions</strong> (<code>view_dashboard</code>, <code>view_tenants</code>, <code>manage_tenant_users</code>, <code>view_billing</code>, <code>manage_settings</code>, <code>view_changelog</code>). When a button is missing, the most likely reason is that the corresponding action is not granted to your role.</p><p>The three standard portal roles are:</p><ul><li><strong>Owner</strong> — full control of the customer. Manages tenants, users, billing, and settings.</li><li><strong>Admin</strong> — manages tenants, users, and some of the customer configuration.</li><li><strong>Member</strong> — limited access, typically used for tenant-scoped users.</li></ul><p>See <a href="./../concepts/roles-and-permissions">Roles &amp; Permissions</a> for the underlying model.</p><h2 id="common-patterns" tabindex="-1">Common patterns <a class="header-anchor" href="#common-patterns" aria-label="Permalink to &quot;Common patterns&quot;">​</a></h2><p>The Customer Portal uses the same conventions as the Admin Console:</p><ul><li>Search and filter at the top of each list page.</li><li>Status badges in green / orange / red / grey.</li><li>Destructive actions confirm in a modal.</li><li>Detail pages open from clicking a row.</li></ul><p>Customers do <strong>not</strong> see the platform-wide pages (cross-customer dashboard, audit log, system pages, finance dashboards across all customers). Those are operator-only.</p>',17)])])}const b=t(i,[["render",d]]);export{u as __pageData,b as default};
